implementations.Rust:
// Rust implementation should follow semantic specification
// Use Rust idioms while maintaining mathematical equivalence

pub fn hrf_spmg1(t: &[f64], p1: f64, p2: f64, a1: f64) -> Vec<f64> {
    const C: f64 = 1.274527e-13;

    t.iter()
        .map(|&time| {
            if time < 0.0 {
                0.0
            } else {
                (-time).exp() * (a1 * time.powf(p1) - C * time.powf(p2))
            }
        })
        .collect()
}

// Default parameter wrapper
pub fn hrf_spmg1_default(t: &[f64]) -> Vec<f64> {
    hrf_spmg1(t, 5.0, 15.0, 0.0833)
}
